void solve(int CASE)
{
    ll n, q; cin >> n >> q;
    var a = vector<ll>(n + 1);
    ll ans = 0;
    fa(i, 1, n)cin >> a[i], ans ^= a[i];
    var s = vector<int>(n + 2);
    fa(i, 1, n + 1)s[i] = i;
    var find = [&](var find, int x)->int {
        if (s[x] == x)return x;
        return s[x] = find(find, s[x]);
        };
    while (q--) {
        int op; cin >> op;
        if (op == 1) {
            ll l, r; cin >> l >> r;
            for (int i = find(find, l); i <= r; i = find(find, i + 1)) {
                ans ^= a[i];
                a[i] /= (i - l + 1ll);
                ans ^= a[i];
                if (a[i] == 0)s[i] = find(find, i + 1);
            }
        }
        else cout << ans << endl;
    }
    return;
}
